#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool canConstructBST(vector<int>& sequence) {
        int n = sequence.size();
        int i = 0;
        while (i + 1 < n && sequence[i] < sequence[i + 1]) {
            i++;
        }
        if (i == n - 1) {
            return true;
        }
        int root = sequence[i];
        for (int j = i + 1; j < n; j++) {
            if (sequence[j] >= root) {
                return false;
            }
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> sequence(n);
    for (int i = 0; i < n; i++) cin >> sequence[i];
    Solution sol;
    bool ans = sol.canConstructBST(sequence);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
